      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche product = trade.getProduct();
    LocalDate referenceDate = ratesProvider.getValuationDate();

    CurrencyAmount pv = productPricer.presentValue(product, ratesProvider, referenceDate, priceType, refData);

    // Add upfront fee
    if (trade.getUpfrontFee().isPresent()) {
      Payment fee = trade.getUpfrontFee().get();
      if (fee.getDate().isEqual(referenceDate) || fee.getDate().isAfter(referenceDate)) {
        CurrencyAmount feeAmount = CurrencyAmount.of(fee.getCurrency(), fee.getAmount());
        pv = pv.plus(feeAmount);
      } else {
        // Discount the fee to reference date
        double df = ratesProvider.discountFactors(fee.getCurrency()).discountFactor(fee.getDate());
        CurrencyAmount discountedFee = CurrencyAmount.of(fee.getCurrency(), fee.getAmount() * df);
